import React from "react";
import UpdateProfile from "./UpdateProfile";
import DeleteAccount from "./DeleteAccount";


const ProfilePage: React.FC = () => {
    return (
        <div className="profile-page">
            <div className="profile-wrapper">
                {/* Pătratul din stânga */}
                <div className="profile-container">
                    <h1>Profilul Meu</h1>
                    <UpdateProfile />
                    <hr className="profile-divider" />
                    <DeleteAccount />
                </div>

                {/* Pătratul din dreapta */}
                <div className="profile-container">
                    <h1>Informații Cont</h1>
                    <p>Aici poți afișa alte detalii despre utilizator:</p>
                    <ul style={{ textAlign: 'left', lineHeight: '1.8' }}>
                        <li>Nume utilizator: [Username]</li>
                        <li>Rol: [Rolul Utilizatorului]</li>
                        <li>Membru din: [Data Creării]</li>
                        <li>Teste completate: [Număr]</li>
                    </ul>
                </div>
            </div>
        </div>
    );
};

export default ProfilePage;
